// 1. Standart Numeric Enums
enum Day {
  Monday,
  Tuesday,
  Wednesday
}
const today: Day = Day.Monday;
console.log(today); // Çıxış: 0
console.log(Day[0]); // Çıxış: Monday
console.log(Day.Tuesday); // Çıxış: 1

// 2. Xüsusi dəyərlərlə Numeric Enums
enum Status {
  Active = 1,
  Inactive = 0,
  Pending = 2
}
const userStatus: Status = Status.Active;
console.log(userStatus); // Çıxış: 1
console.log(Status[userStatus]); // Çıxış: Active

// 3. Numeric Enums funksiyalarda
enum Direction {
  Up = 1,
  Down = 2,
  Left = 3,
  Right = 4
}
function move(direction: Direction): string {
  switch (direction) {
    case Direction.Up: return "Yuxarı hərəkət";
    case Direction.Down: return "Aşağı hərəkət";
    default: return "Hərəkət yoxdur";
  }
}
console.log(move(Direction.Up)); // Çıxış: Yuxarı hərəkət

// 4. Numeric Enums ilə interfeyslər
interface User {
  id: number;
  status: Status;
}
const user: User = { id: 1, status: Status.Active };
console.log(user); // Çıxış: { id: 1, status: 1 }

// 5. Numeric Enums ilə union tipləri
type Action = Direction | 0;
function handleAction(action: Action): string {
  if (action === 0) return "Dayan";
  return move(action);
}
console.log(handleAction(0)); // Çıxış: Dayan
console.log(handleAction(Direction.Left)); // Çıxış: Hərəkət yoxdur

// 6. Const Numeric Enums
const enum Role {
  Admin = 1,
  User = 2,
  Guest = 3
}
const userRole: Role = Role.Admin;
console.log(userRole); // Çıxış: 1

// 7. Reverse Mapping
enum Priority {
  Low,
  Medium,
  High
}
console.log(Priority[1]); // Çıxış: Medium
console.log(Priority.High); // Çıxış: 2

// Sadə mağaza sistemi
enum OrderStatus {
  Pending = 1,
  Shipped = 2,
  Delivered = 3
}
interface Order {
  id: string;
  productName: string;
  status: OrderStatus;
}
class OrderItem implements Order {
  id: string;
  productName: string;
  status: OrderStatus;
  constructor(id: string, productName: string, status: OrderStatus) {
    this.id = id;
    this.productName = productName;
    this.status = status;
  }
  getDetails(): string {
    return `${this.productName} (ID: ${this.id}, Status: ${OrderStatus[this.status]})`;
  }
}
const order = new OrderItem("O001", "Laptop", OrderStatus.Shipped);
console.log(order.getDetails()); // Çıxış: Laptop (ID: O001, Status: Shipped)

// Enum ilə funksiya
function checkStatus(status: OrderStatus): string {
  switch (status) {
    case OrderStatus.Pending: return "Sifariş gözləyir";
    case OrderStatus.Shipped: return "Sifariş göndərilib";
    case OrderStatus.Delivered: return "Sifariş çatdırılıb";
    default: return "Bilinməyən status";
  }
}
console.log(checkStatus(OrderStatus.Delivered)); // Çıxış: Sifariş çatdırılıb

